#nullable enable // autogenerated

namespace MVZ2Logic.Options
{
    public abstract class OptionToggleDefinition : OptionWidgetDefinition
    {
        public OptionToggleDefinition(string nsp, string name) : base(nsp, name)
        {
        }
        public override OptionWidgetType GetItemType()
        {
            return OptionWidgetType.Toggle;
        }
        public abstract bool GetValue(IOptionContext context);
        public abstract void OnValueChanged(IOptionContext context, bool value);
    }
}
